import{_ as a,o as t,c as s,a2 as i}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 34 — Advanced Replace","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/34-replace.md","filePath":"chapters/34-replace.md"}'),n={name:"chapters/34-replace.md"};function o(c,e,l,p,r,d){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="chapter-34-—-advanced-replace" tabindex="-1">Chapter 34 — Advanced Replace <a class="header-anchor" href="#chapter-34-—-advanced-replace" aria-label="Permalink to &quot;Chapter 34 — Advanced Replace&quot;">​</a></h1><blockquote><p><em>&quot;Replace isn&#39;t just find-and-replace. It&#39;s a transformation language.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐⭐ Advanced <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>The <code>:s</code> command can do more than simple substitutions.</p><hr><h1 id="replace-with-confirmation" tabindex="-1">Replace with Confirmation <a class="header-anchor" href="#replace-with-confirmation" aria-label="Permalink to &quot;Replace with Confirmation&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/old/new/gc</span></span></code></pre></div><p>Vim asks at each match:</p><ul><li><code>y</code> — Replace this match</li><li><code>n</code> — Skip this match</li><li><code>a</code> — Replace all remaining</li><li><code>q</code> — Quit</li><li><code>l</code> — Replace this and quit</li></ul><hr><h1 id="replace-with-expressions" tabindex="-1">Replace with Expressions <a class="header-anchor" href="#replace-with-expressions" aria-label="Permalink to &quot;Replace with Expressions&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:%s/\\v\\d+/\\=submatch(0) + 1/g</span></span></code></pre></div><p>Increment every number in the file.</p><hr><h1 id="replace-in-a-range" tabindex="-1">Replace in a Range <a class="header-anchor" href="#replace-in-a-range" aria-label="Permalink to &quot;Replace in a Range&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:10,20s/foo/bar/g</span></span></code></pre></div><p>Replace only in lines 10-20.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:.,$s/foo/bar/g</span></span></code></pre></div><p>Replace from cursor to end.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:&#39;&lt;,&#39;&gt;s/foo/bar/g</span></span></code></pre></div><p>Replace in visual selection (automatic when selecting then <code>:</code>).</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>:s</code> with <code>c</code> flag adds confirmation.</li><li><code>\\=</code> expressions compute replacements.</li><li>Visual selection auto-populates the range.</li></ul><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./35-registers.html"><strong>Chapter 35 — Registers</strong></a></p><p>Master Vim&#39;s multiple clipboards.</p>',31)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
